data.content:
Here are the MSTest comparison assertions you should use and a complete test class:

**Key assertions for boundary checking:**

| Assertion | Use case |
|-----------|----------|
| `Assert.IsInRange(actual, low, high)` | Percentage is within valid bounds (0–100) |
| `Assert.IsGreaterThan(lowerBound, actual)` | Score exceeds a threshold |
| `Assert.IsLessThan(upperBound, actual)` | Score is below a ceiling |
| `Assert.ThrowsExactly<T>(...)` | Invalid inputs throw |

Here's a complete test class:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(5, 10, 50.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_AnyValidInputs_ReturnsValueInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50, 100);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultAlwaysInRange()
    {
        var result = _calculator.NormalizeScore(75, 200);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_IsLessThan100()
    {
        var result = _calculator.NormalizeScore(80, 100);
        Assert.IsLessThan(100.0, result);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Summary of the comparison assertions:**

- **`Assert.IsInRange(actual, low, high)`** — verifies a value falls within bounds (inclusive). Perfect for "percentage must be 0–100".
- **`Assert.IsGreaterThan(lowerBound, actual)`** — verifies actual > lowerBound.
- **`Assert.IsLessThan(upperBound, actual)`** — verifies actual < upperBound.

These produce clear failure messages like `"Expected value to be in range [0, 100], but was 105"` — far better than `Assert.IsTrue(x >= 0 && x <= 100)`.
